-- Add law_context to categories: editorial "In context" copy for law detail pages (one per category).
-- Populated so every law gets category-specific copy from the database.

ALTER TABLE categories ADD COLUMN law_context TEXT;

UPDATE categories SET law_context = 'Murphy''s Law and its corollaries capture a universal truth about risk and human error: when stakes are high, the unexpected becomes inevitable. Engineers and safety experts use these principles to design for failure and reduce harm.', updated_at = strftime('%Y-%m-%dT%H:%M:%fZ', 'now') WHERE slug = 'murphys-laws';
